12	// Wrap raw LINEAR16 PCM bytes in a WAV container so browsers can decode it
13	function pcmToWav(pcmBuffer: Buffer, sampleRate = 24000, channels = 1, bitDepth = 16): Buffer {
14	  const byteRate = sampleRate * channels * (bitDepth / 8);
15	  const blockAlign = channels * (bitDepth / 8);
16	  const header = Buffer.alloc(44);
17	  header.write('RIFF', 0);
18	  header.writeUInt32LE(36 + pcmBuffer.length, 4);
19	  header.write('WAVE', 8);
20	  header.write('fmt ', 12);
21	  header.writeUInt32LE(16, 16);
22	  header.writeUInt16LE(1, 20);       // PCM
23	  header.writeUInt16LE(channels, 22);
24	  header.writeUInt32LE(sampleRate, 24);
25	  header.writeUInt32LE(byteRate, 28);
26	  header.writeUInt16LE(blockAlign, 32);
27	  header.writeUInt16LE(bitDepth, 34);
28	  header.write('data', 36);
29	  header.writeUInt32LE(pcmBuffer.length, 40);
30	  return Buffer.concat([header, pcmBuffer]);
31	}
