33	export async function POST(req: NextRequest) {
34	  try {
35	    const { text } = (await req.json()) as { text?: string };
36	    if (!text?.trim()) return NextResponse.json({ error: 'No text provided' }, { status: 400 });
37	
38	    const safeText = text.slice(0, 2000);
39	
40	    for (const key of _KEYS) {
41	      try {
42	        const res = await fetch(
43	          `https://generativelanguage.googleapis.com/v1beta/models/${TTS_MODEL}:generateContent?key=${key}`,
44	          {
45	            method: 'POST',
46	            headers: { 'Content-Type': 'application/json' },
47	            body: JSON.stringify({
48	              contents: [{ parts: [{ text: safeText }] }],
49	              generationConfig: {
50	                responseModalities: ['AUDIO'],
51	                speechConfig: {
52	                  voiceConfig: { prebuiltVoiceConfig: { voiceName: TTS_VOICE } },
53	                },
54	              },
55	            }),
56	          }
57	        );
58	
59	        if (!res.ok) { console.warn(`[TTS] Key failed — status ${res.status}`); continue; }
60	
61	        const data = await res.json();
62	        // eslint-disable-next-line @typescript-eslint/no-explicit-any
63	        const part = data.candidates?.[0]?.content?.parts?.find((p: any) => p.inlineData);
64	        if (!part?.inlineData?.data) continue;
65	
66	        const pcm = Buffer.from(part.inlineData.data, 'base64');
67	        const wav = pcmToWav(pcm);
68	        const wavB64 = wav.toString('base64');
69	
70	        return NextResponse.json({ audio: wavB64, mimeType: 'audio/wav' });
71	      } catch (e) {
72	        console.warn('[TTS] Key failed:', e);
73	      }
74	    }
75	
76	    return NextResponse.json({ error: 'TTS unavailable' }, { status: 503 });
77	  } catch (err) {
78	    return NextResponse.json({ error: String(err) }, { status: 500 });
79	  }
80	}
