199	/* ────────────────────────────────────────────
200	   PCM audio playback
201	   ──────────────────────────────────────────── */
202	function playPCM(base64: string) {
203	  const binary = atob(base64);
204	  const bytes = new Uint8Array(binary.length);
205	  for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
206	
207	  const header = new ArrayBuffer(44);
208	  const view = new DataView(header);
209	  const sampleRate = 24000;
210	  view.setUint32(0, 0x52494646, false);
211	  view.setUint32(4, 36 + bytes.length, true);
212	  view.setUint32(8, 0x57415645, false);
213	  view.setUint32(12, 0x666d7420, false);
214	  view.setUint32(16, 16, true);
215	  view.setUint16(20, 1, true);
216	  view.setUint16(22, 1, true);
217	  view.setUint32(24, sampleRate, true);
218	  view.setUint32(28, sampleRate * 2, true);
219	  view.setUint16(32, 2, true);
220	  view.setUint16(34, 16, true);
221	  view.setUint32(36, 0x64617461, false);
222	  view.setUint32(40, bytes.length, true);
223	
224	  return new Audio(URL.createObjectURL(new Blob([header, bytes], { type: 'audio/wav' })));
225	}
